import liChoose from '@/components/li-choose/li-choose.vue';
import sharePerson from '@/components/share-person/share-person.vue';
import qiniuUploader from '@/common/qiniuUploader.js';
import wPicker from '@/components/w-picker/w-picker.vue';
export default {
	data() {
		return {
			mode: false,
			index: -1,
			customerSource: ['自然到访', '渠道', '分销', '老带新', '电转访', '自拓', '其他'], //1-自然到访，2-渠道，3-分销，4-老带新，5-电转访，6-自拓，7-其他
			customerGender: [],
			customerAge: [],
			customerHouseType: [],
			customerBuyHousePurpose: [],
			modalName: null,
			imgList: [],
			pid: '', //项目id
			showCustomer: false,
			isSingle: true, //选择项目是否是单选
			p_name: '请选择项目', //选择项目
			templateList: [],
			activeIndex: 0,
			sharePersonData: [], //置业顾问
			sharePersons: '请选择共享人',
			qiniuDatas: '', //七牛云token
			formData: {
				pid: '',
				project_template: '', //模板
				source_type: 0, //客户来源（1-自然到访，2-渠道）
				visit_type: '', //到访情况 (1:面谈，2：非面谈)
				cname: '', //客户姓名
				ctel: '', //电话
				ctimestr: '', //首访时间戳
				ctels: '', //备用手机号
				idcard: '', //身份证号码
				address: '', //联系地址
				tips: '', //备注信息
				resistance_point: '', //抗性点
				agree_point: '', //	否	string	认同点
				suggest_point: '', //	否	string	突破建议
				transaction_point: '', //	否	string	成交重点
				attribution: '', //	否	string	客户归属
				focus_project: '', //	否	string	关注项目
				share_str: '', //	否	string	分享人
				photo: '', //	否	array	客户照片
				tmp_id: '' ,//否	string	关联人脸信息id
				id:''
			},
			firstTime: '',
			JttemplateList: [],
			customerData: ''
		};
	},
	components: {
		liChoose,
		sharePerson,
		wPicker
	},
	onLoad(option) {
		if (option.id) {
			this.id = option.id;
			this.getCustomerInfo();
		}
		this.getBigareacustomapi();
		this.getQiniuToken();
		this.getJtTemplate();
	},
	computed: {
		nowDay() {
			let date = new Date();
			return date.getFullYear() + '' + (date.getMonth() + 1) + '' + date.getDate();
		}
	},
	methods: {
		getCustomerInfo() {
			let data = {
				id: this.id
			};
			this.$api.getInfocustomapi(data, res => {
				this.customerData = res.data;
				this.pid = this.customerData.pid;
				this.firstTime = this.customerData.ctimestr;
				this.formData.id = this.customerData.id;
				this.formData.cname = this.customerData.cname;
				this.formData.ctel = this.customerData.ctel;
				this.formData.ctels = this.customerData.ctels;
				this.formData.share_str = this.customerData.share_str;
				this.formData.pid = this.customerData.pid;
				this.formData.resistance_point = this.customerData.resistance_point;
				this.formData.agree_point = this.customerData.agree_point;
				this.formData.suggest_point = this.customerData.suggest_point;
				this.formData.transaction_point = this.customerData.transaction_point;
				this.formData.attribution = this.customerData.attribution;
				this.sharePersons = this.customerData.share_name;
				this.formData.project_template = this.customerData.project_template;
				this.imgList = this.customerData.photo;
				this.p_name = this.customerData.p_name;
				if(this.firstTime){
					this.formData.ctimestr = this.$tools.timeToTimeStamp(this.firstTime);
				}
				
				this.getTemplate();
			});
		},
		//获取项目模板
		getJtTemplate() {
			let data = {
				pid: 0,
				type: 1 //1：录入客户模板；2：跟进客户模板
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetprojecttemplatecustomapi(data, res => {
				this.JttemplateList = [];
				for (let var1 in res.data) {
					let temp = {
						name: res.data[var1].title,
						list: [],
						key: var1,
						idIndex: 0,
						empty: res.data[var1].empty, ////是否必选（1-非必选，2-必选）
						type: res.data[var1].type, //0 select 单选  1 check-box  复选 2 radio单选
						enable: res.data[var1].enable //是否启用（1-启用，2-禁用）
					};
					res.data[var1].option_data.forEach(res => {
						let datas = {
							name: res,
							active: false
						};
						temp.list.push(datas);
					});
					this.JttemplateList.push(temp);
				}
			});
		},
		inputTel(e) {
			this.$tools.isPhone(e.detail.value);
		},
		inputIdcard(e) {
			this.$tools.isIdCard(e.detail.value);
		},
		//根据权限获取大区和大区下的项目
		getBigareacustomapi() {
			uni.showLoading({
				title: '正在获取数据...'
			});
			this.$api.customGetbigareacustomapi({}, res => {
				res.data.forEach(res => {
					res.project.forEach(resp => {
						resp.isactive = false;
					});
				});
				this.$store.commit('setSearchPro', res.data);
			});
		},
		showTimes() {
			this.$refs.dateTime.show();
		},
		onConfirm(res) {
			//时间选择
			this.firstTime = res.result;
			this.formData.ctimestr = this.$tools.timeToTimeStamp(this.firstTime);
		},
		chooseProject() {
			this.$refs.lichoose.show();
		},
		confirms(res) {
			this.pid = res.pid[0];
			this.formData.pid = this.pid;
			this.p_name = res.p_name;
			this.getsaleslistcustomapi();
			this.getTemplate();
		},
		PickerChange(e) {
			this.formData.source_type = e.detail.value;
		},
		PickerChangeGender(e) {
			let id = e.target.id;
			let index = e.detail.value;
			this.JttemplateList.forEach(res => {
				if (res.key == id) {
					res.idIndex = index;
				}
			});
		},
		//客户年龄
		PickerChangeAge(e) {},
		//意向房型
		PickerChangeHouse(e) {},
		//置业目的
		PickerChangeBuyHousePurpose(e) {},
		textareaAInput(e) {
			this.textareaAValue = e.detail.value;
		},
		ViewImage(e) {
			uni.previewImage({
				urls: this.imgList,
				current: e.currentTarget.dataset.url
			});
		},
		DelImg(e) {
			uni.showModal({
				title: '提示',
				content: '确定删除？',
				cancelText: '取消',
				confirmText: '确定',
				success: res => {
					if (res.confirm) {
						this.imgList.splice(e.currentTarget.dataset.index, 1);
					}
				}
			});
		},
		ChooseImage() {
			uni.chooseImage({
				count: 9, //默认9
				sizeType: ['original', 'compressed'], //可以指定是原图还是压缩图，默认二者都有
				sourceType: ['album'], //从相册选择
				success: res => {
					if (this.imgList.length != 0) {
						this.imgList = this.imgList.concat(res.tempFilePaths);
					} else {
						this.imgList = res.tempFilePaths;
					}
				}
			});
		},
		getsaleslistcustomapi() {
			//获取项目下的置业顾问
			let data = {
				pid: this.pid
			};
			uni.showLoading({
				title: '正在获取置业顾问数据...'
			});
			this.$api.getSaleslistcustomapi(data, res => {
				this.sharePersonData = res.data.data;
			});
		},
		//获取项目模板
		getTemplate() {
			let data = {
				pid: this.pid,
				type: 1 //1：录入客户模板；2：跟进客户模板
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetprojecttemplatecustomapi(data, res => {
				this.templateList = [];
				for (let var1 in res.data) {
					let temp = {
						name: res.data[var1].title,
						list: [],
						key: var1,
						empty: res.data[var1].empty, ////是否必选（1-非必选，2-必选）
						type: res.data[var1].type, //0 select 单选  1 check-box  复选 2 radio单选
						enable: res.data[var1].enable //是否启用（1-启用，2-禁用）
					};
					res.data[var1].option_data.forEach(res => {
						let datas = {
							name: res,
							active: false
						};
						temp.list.push(datas);
					});
					this.templateList.push(temp);
				}
			});
		},
		chooseTemp(item, index, items) {
			item.index = index;
			//0 select 单选  1 check-box  复选 2 radio单选
			if (items.type == 1) {
				item.active = !item.active;
			} else {
				items.list.forEach(res => {
					res.active = false;
				});
				item.active = !item.active;
			}
			this.$forceUpdate();
		},
		async sub() {
			if (!this.formData.pid) {
				uni.showToast({
					icon: 'none',
					title: '请选择项目'
				});
				return;
			}
			if (!this.formData.cname) {
				uni.showToast({
					icon: 'none',
					title: '请输入客户姓名'
				});
				return;
			}
			if (!this.formData.ctel) {
				uni.showToast({
					icon: 'none',
					title: '请输入客户联系方式'
				});
				return;
			}
			if (!this.$tools.isPhone(this.formData.ctel)) {
				uni.showToast({
					icon: 'none',
					title: '请输入正确的手机号'
				});
				return;
			}
			if (this.formData.idcard) {
				if (!this.$tools.isIdCard(this.formData.idcard)) {
					uni.showToast({
						icon: 'none',
						title: '请输入正确的身份证号码'
					});
					return;
				}
			}
			this.formData.project_template = [];
			if (!this.templateList) {
				uni.showToast({
					icon: 'none',
					title: '请先选择项目模板'
				});
				return;
			}
			if (!this.formData.ctimestr) {
				uni.showToast({
					icon: 'none',
					title: '请选择客户来访时间'
				});
				return;
			}
			let obj = {};
			for (let var1 in this.templateList) {
				let keyValue = {};
				let key = this.templateList[var1].key;
				keyValue[key] = [];
				this.templateList[var1].list.forEach(resp => {
					if (resp.active == true) {
						keyValue[key].push(resp.index);
					}
				});
				if (keyValue[key].length == 0 && this.templateList[var1].empty == 2) {
					uni.showToast({
						icon: 'none',
						title: this.templateList[var1].name + '必须选择'
					});
					return;
				}
				obj[key] = keyValue[key];
			}
			for (let var1 in this.JttemplateList) {
				let keyValue = {};
				let key = this.JttemplateList[var1].key;
				keyValue[key] = [];
				this.JttemplateList.forEach(resp => {
					if (resp.key == key) {
						keyValue[key].push(resp.idIndex);
					}
				});
				obj[key] = keyValue[key];
			}
			this.formData.project_template = obj;
			uni.showLoading({
				title: '正在上传数据...'
			});
			this.formData.photo = ''; //七牛云图片名
			if (this.imgList.length !== 0) {
				try {
					this.formData.photo = await this.imageUploads();
				} catch (e) {
					//TODO handle the exception
				}
			}
			this.$api.EditCustomapi(this.formData, res => {
				if(res.code == 1000){
					uni.showToast({
						icon: 'none',
						title: '修改成功'
					});
					setTimeout(() =>{
						uni.navigateBack({
							delta:1
						})
					},1000)
				}else{
					uni.showToast({
						icon:'none',
						title:res.msg
					})
				}
			});
		},
		showShare() {
			if (this.sharePersonData.length != 0) {
				this.$refs.sharePersons.open();
			} else {
				uni.showToast({
					icon: 'none',
					title: '此项目无共享人'
				});
			}
		},
		getQiniuToken() {
			uni.showLoading({
				title: '正在获取数据...'
			});
			this.$api.qiniuTokencustomapi({}, res => {
				this.qiniuDatas = res;
			});
		},
		imageUploads() {
			let _this = this;
			return new Promise(resolve => {
				let keys = [];
				let token = this.qiniuDatas.token;
				let domain = this.qiniuDatas.http_domain;
				let bucket = this.qiniuDatas.bucket;
				_this.imgList.forEach(filePath => {
					let key = 'sunest-' + this.nowDay + '-' + new Date().getTime() + '.jpg';
					keys.push(key);
					qiniuUploader.upload(
						filePath,
						res => {
							// console.log('ressss: ' + JSON.stringify(res));
						},
						error => {
							// resolve(error)
						},
						{
							region: 'SCN', // ECN, SCN, NCN, NA, ASG，分别对应七牛的：华东，华南，华北，北美，新加坡 5 个区域
							domain: domain, // // bucket 域名，下载资源时用到。如果设置，会在 success callback 的 res 参数加上可以直接使用的 ImageURL 字段。否则需要自己拼接
							key: key, // [非必须]自定义文件 key。如果不设置，默认为使用微信小程序 API 的临时文件名
							// 以下方法三选一即可，优先级为：uptoken > uptokenURL > uptokenFunc
							uptoken: token // 由其他程序生成七牛 uptoken
						},
						res => {
							if (res.progress === 100) {
								resolve(keys);
							}
						}
					);
				});
			});
		},
		onShares(data) {
			this.$refs.sharePersons.close();
			let ids = [];
			let names = [];
			if (data) {
				data.forEach(res => {
					ids.push(res.u_id);
					names.push(res.u_name);
				});
			}
			this.sharePersons = this.$tools.toStrings(names);
			this.formData.share_str = this.$tools.toStrings(ids);
		}
	}
};
